<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;use App\Services\DocumentService;use App\Services\EmailService;use App\Services\SharePointService;use App\Services\TeamsService;
final class InvoiceController
{
    public function index(): void { Auth::requireLogin();$rows=Database::connection()->query('SELECT i.*,c.display_name FROM invoices i JOIN customers c ON c.id=i.customer_id ORDER BY i.created_at DESC')->fetchAll();View::render('portal/invoices/index',['title'=>'Invoices','invoices'=>$rows],'portal');}
    public function create(): void { Auth::requireLogin();$pdo=Database::connection();$jobs=$pdo->query("SELECT j.id,j.job_number,j.customer_id,j.estimate_id,c.display_name,e.total estimate_total FROM jobs j JOIN customers c ON c.id=j.customer_id LEFT JOIN estimates e ON e.id=j.estimate_id WHERE j.status='completed' AND NOT EXISTS(SELECT 1 FROM invoices i WHERE i.job_id=j.id) ORDER BY j.updated_at DESC")->fetchAll();View::render('portal/invoices/form',['title'=>'New Invoice','jobs'=>$jobs],'portal');}
    public function store(): void { Auth::requireLogin();verify_csrf();$pdo=Database::connection();$jobId=(int)$_POST['job_id'];$s=$pdo->prepare('SELECT j.*,e.subtotal,e.tax_amount,e.total FROM jobs j LEFT JOIN estimates e ON e.id=j.estimate_id WHERE j.id=?');$s->execute([$jobId]);$j=$s->fetch();$total=(float)($j['total']??$_POST['total']??0);$subtotal=(float)($j['subtotal']??$total);$tax=(float)($j['tax_amount']??0);$num=next_number('INV-');$q=$pdo->prepare('INSERT INTO invoices(invoice_number,public_token,customer_id,job_id,status,issue_date,due_date,subtotal,tax_amount,total,balance_due) VALUES(?,?,?,?,?,?,?,?,?,?,?)');$q->execute([$num,public_token(),$j['customer_id'],$jobId,'draft',date('Y-m-d'),$_POST['due_date']?:date('Y-m-d'),$subtotal,$tax,$total,$total]);$id=(int)$pdo->lastInsertId();AuditService::log('invoice.created','invoice',$id);flash('success','Invoice created.');redirect('/portal/invoices/'.$id);}
    public function show(string $id): void { Auth::requireLogin();$pdo=Database::connection();$s=$pdo->prepare('SELECT i.*,c.display_name,c.email,c.phone,j.job_number,j.service_summary FROM invoices i JOIN customers c ON c.id=i.customer_id LEFT JOIN jobs j ON j.id=i.job_id WHERE i.id=?');$s->execute([(int)$id]);$invoice=$s->fetch();if(!$invoice){http_response_code(404);exit('Invoice not found.');}$p=$pdo->prepare('SELECT * FROM payments WHERE invoice_id=? ORDER BY received_at DESC');$p->execute([(int)$id]);$d=$pdo->prepare("SELECT * FROM documents WHERE reference_type='invoice' AND reference_id=? ORDER BY created_at DESC");$d->execute([(int)$id]);$ps=$pdo->prepare('SELECT * FROM payment_sessions WHERE invoice_id=? ORDER BY created_at DESC LIMIT 5');$ps->execute([(int)$id]);View::render('portal/invoices/show',['title'=>$invoice['invoice_number'],'invoice'=>$invoice,'payments'=>$p->fetchAll(),'documents'=>$d->fetchAll(),'paymentSessions'=>$ps->fetchAll()],'portal');}
    public function payment(string $id): void { Auth::requireLogin();verify_csrf();$amount=(float)$_POST['amount'];$pdo=Database::connection();$pdo->beginTransaction();try{$p=$pdo->prepare('INSERT INTO payments(invoice_id,amount,method,reference) VALUES(?,?,?,?)');$p->execute([(int)$id,$amount,$_POST['method'],trim($_POST['reference']??'')]);$s=$pdo->prepare('SELECT total,COALESCE((SELECT SUM(amount) FROM payments WHERE invoice_id=?),0) paid FROM invoices WHERE id=?');$s->execute([(int)$id,(int)$id]);$i=$s->fetch();$balance=max(0,(float)$i['total']-(float)$i['paid']);$status=$balance<=0?'paid':'sent';$pdo->prepare('UPDATE invoices SET balance_due=?,status=? WHERE id=?')->execute([$balance,$status,(int)$id]);$pdo->commit();AuditService::log('payment.recorded','invoice',(int)$id,['amount'=>$amount]);try{(new TeamsService())->send('Payment recorded',money($amount).' was recorded on invoice '.$id);}catch(\Throwable){}try{$r=$pdo->prepare('SELECT i.invoice_number,i.balance_due,c.display_name,c.email FROM invoices i JOIN customers c ON c.id=i.customer_id WHERE i.id=?');$r->execute([(int)$id]);$receipt=$r->fetch();if($receipt&&$receipt['email']){(new EmailService())->sendMail($receipt['email'],'Payment receipt for invoice '.$receipt['invoice_number'],'<p>Hello '.e($receipt['display_name']).',</p><p>Thank you. We received your payment of <strong>'.money($amount).'</strong>.</p><p>Remaining balance: <strong>'.money($receipt['balance_due']).'</strong>.</p>');}}catch(\Throwable){}flash('success','Payment recorded and receipt processed.');}catch(\Throwable $e){$pdo->rollBack();flash('danger',$e->getMessage());}redirect('/portal/invoices/'.$id);}
    public function send(string $id): void { Auth::requireLogin();verify_csrf();$pdo=Database::connection();$s=$pdo->prepare('SELECT i.*,c.display_name,c.email FROM invoices i JOIN customers c ON c.id=i.customer_id WHERE i.id=?');$s->execute([(int)$id]);$i=$s->fetch();try{$doc=(new DocumentService())->generate('invoice',(int)$id);$sp=new SharePointService();if($sp->configured()){try{$remote=(string)\App\Core\Env::get('M365_SHAREPOINT_BASE_FOLDER','Exterior Services').'/Invoices/'.$doc['filename'];$up=$sp->upload($doc['path'],$remote);$pdo->prepare("UPDATE documents SET storage_status='uploaded',sharepoint_item_id=?,sharepoint_url=? WHERE id=?")->execute([$up['id']??null,$up['webUrl']??null,$doc['id']]);}catch(\Throwable $x){$pdo->prepare("UPDATE documents SET storage_status='failed',upload_error=? WHERE id=?")->execute([$x->getMessage(),$doc['id']]);}}$url=rtrim((string)\App\Core\Env::get('APP_URL',''),'/').'/invoice/'.$i['public_token'];(new EmailService())->sendMail($i['email'],'Invoice '.$i['invoice_number'].' from Rock Bluffs Exterior Services','<p>Hello '.e($i['display_name']).',</p><p>Your invoice total is <strong>'.money($i['total']).'</strong>.</p><p><a href="'.$url.'">View and pay invoice</a></p><p>Balance due: <strong>'.money($i['balance_due']).'</strong>.</p>',['path'=>$doc['path'],'name'=>$doc['filename'],'type'=>'application/pdf']);$pdo->prepare("UPDATE invoices SET status='sent' WHERE id=?")->execute([(int)$id]);$pdo->prepare("INSERT INTO notification_logs(customer_id,entity_type,entity_id,channel,template_key,recipient,subject,status,sent_at) VALUES(?, 'invoice', ?, 'email','invoice_sent',?,?,'sent',NOW())")->execute([$i['customer_id'],(int)$id,$i['email'],'Invoice '.$i['invoice_number']]);AuditService::log('invoice.sent','invoice',(int)$id);flash('success','Invoice PDF generated, archived, and sent through the configured email provider.');}catch(\Throwable $e){flash('danger','Invoice send failed: '.$e->getMessage());}redirect('/portal/invoices/'.$id);}
}
